import{_ as t,o,c as s,ag as a}from"./chunks/framework.DZKik_R9.js";const p=JSON.parse('{"title":"Visiteur, sticky et persistance des assignations","description":"","frontmatter":{},"headers":[],"relativePath":"solution/visitor-assignments.md","filePath":"solution/visitor-assignments.md"}'),i={name:"solution/visitor-assignments.md"};function n(r,e,c,d,l,u){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="visiteur-sticky-et-persistance-des-assignations" tabindex="-1">Visiteur, sticky et persistance des assignations <a class="header-anchor" href="#visiteur-sticky-et-persistance-des-assignations" aria-label="Permalink to &quot;Visiteur, sticky et persistance des assignations&quot;">​</a></h1><p>Ce document décrit le comportement du <strong>remote</strong> (<code>apps/remote</code>) et son lien avec <code>POST /api/evaluate</code>.</p><h2 id="identifiant-visiteur-context-userid" tabindex="-1">Identifiant visiteur (<code>context.userId</code>) <a class="header-anchor" href="#identifiant-visiteur-context-userid" aria-label="Permalink to &quot;Identifiant visiteur (`context.userId`)&quot;">​</a></h2><p>Le remote remplit <strong><code>userId</code></strong> dans le contexte envoyé au moteur :</p><ul><li><strong>Clé <code>localStorage</code></strong> : <code>abtest_visitor_id</code></li><li><strong>Cookie miroir</strong> : <code>abtest_vid</code> (first-party, <code>path=/</code>, <code>SameSite=Lax</code>, longue durée)</li></ul><p>À la première visite, un UUID est généré puis réutilisé. Le moteur s’en sert pour le <strong>bucketing</strong> (<code>seed = campaignId:userId</code>) lorsqu’aucune variation sticky n’applique.</p><h3 id="remplacer-l-id-apres-login" tabindex="-1">Remplacer l’id après login <a class="header-anchor" href="#remplacer-l-id-apres-login" aria-label="Permalink to &quot;Remplacer l’id après login&quot;">​</a></h3><p>Le module fédéré expose aussi <strong><code>./visitorId</code></strong> avec <code>setAbtestVisitorId(id)</code> (à appeler <strong>tôt</strong>, id unique, max 255 caractères). Changer d’id <strong>après</strong> une première assignation peut modifier le bucket si le sticky n’est plus présent ; en pratique le <strong>sticky par campagne</strong> reste prioritaire tant qu’il est valide.</p><h2 id="stockage-des-assignations-sticky" tabindex="-1">Stockage des assignations (sticky) <a class="header-anchor" href="#stockage-des-assignations-sticky" aria-label="Permalink to &quot;Stockage des assignations (sticky)&quot;">​</a></h2><ul><li><strong>Source principale</strong> : <code>localStorage</code>, clé <strong><code>abtest_assignments_v1</code></strong>, objet JSON <code>{ &quot;v&quot;: 1, &quot;entries&quot;: { &quot;&lt;campaignId&gt;&quot;: { &quot;variationId&quot;, &quot;expiresAtMs&quot; } } }</code>.</li><li><strong>TTL</strong> : aligné sur <code>campaign.endDate</code> si défini et futur, sinon <strong>30 jours</strong> (même ordre de grandeur que l’ancien cookie).</li><li><strong>Migration</strong> : si une entrée est absente ou expirée, le remote relit l’ancien cookie <strong><code>ab_var_&lt;campaignId&gt;</code></strong>, l’importe dans le store puis <strong>supprime</strong> ce cookie pour éviter deux sources de vérité.</li><li><strong>Mode <code>technical</code></strong> : aucune écriture dans le store (équivalent à l’absence d’ancien cookie d’assignation).</li><li><strong><code>consent_required</code></strong> (mesure sans consentement) : l’entrée campagne est <strong>supprimée</strong> du store et tout cookie <code>ab_var_*</code> restant est effacé.</li></ul><h2 id="file-d-attente-d-evaluation" tabindex="-1">File d’attente d’évaluation <a class="header-anchor" href="#file-d-attente-d-evaluation" aria-label="Permalink to &quot;File d’attente d’évaluation&quot;">​</a></h2><p>Les appels <code>fetch</code> + injection d’assets passent par une <strong>file sérialisée</strong> côté remote pour limiter les courses au chargement (Module Federation, ordre des effets).</p><h2 id="spa-et-re-evaluation" tabindex="-1">SPA et ré-évaluation <a class="header-anchor" href="#spa-et-re-evaluation" aria-label="Permalink to &quot;SPA et ré-évaluation&quot;">​</a></h2><ul><li>Le composant <strong><code>AbTestSlot</code></strong> réagit aux changements de <strong><code>pathname</code> + <code>search</code></strong> (y compris via <code>history.pushState</code> / <code>replaceState</code> patché une fois par onglet).</li><li>Prop optionnelle <strong><code>navigationDependency</code></strong> : à lier par exemple à <strong><code>location.key</code></strong> (React Router) quand l’URL ne change pas mais que la vue métier change, pour forcer une nouvelle évaluation.</li></ul><h2 id="api-diagnostics" tabindex="-1">API : diagnostics <a class="header-anchor" href="#api-diagnostics" aria-label="Permalink to &quot;API : diagnostics&quot;">​</a></h2><p>La réponse de <code>POST /api/evaluate</code> inclut un objet <strong><code>diagnostics</code></strong> :</p><ul><li><strong><code>hadAssignedVariationInRequest</code></strong> : <code>true</code> si <code>context.assignedVariationId</code> était un entier valide dans la requête.</li><li><strong><code>resolvedBySticky</code></strong> : <code>true</code> si la raison moteur est <code>by_sticky_assignment</code>.</li></ul><p>Voir <a href="./../reference/api-overview">Aperçu de l’API</a> pour la liste des valeurs de <strong><code>reason</code></strong>.</p><h2 id="references" tabindex="-1">Références <a class="header-anchor" href="#references" aria-label="Permalink to &quot;Références&quot;">​</a></h2><ul><li><a href="./module-federation">Module Federation et intégration hôte</a></li><li><a href="./consent">Consentement</a></li></ul>',20)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
